VALUES
  ('cpa-moex-00581', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲牧場專門販售肉牛，20X2年5月20日宰殺5隻肉牛共售得$60,000（帳面金額$30,000），另支 付屠宰費用$2,000、運費$2,000以及肉品交易市場規費$2,500，則甲牧場20X2年5月20日應認 列「生物資產當期公允價值減出售成本之變動之利益」金額為多少？', '["$0", "$23,500", "$26,000", "$30,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00582', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '為發展人工智慧生產流程，甲公司於20X1年1月至4月間投入$10,000，於20X1年5月1日證明 該生產流程已達成技術可行性，且甲公司有意圖完成該生產流程，並加以使用或出售，因而 持續於20X1年5月至8月間投入$10,000。但直至20X1年9月1日甲公司才證明有能力完成該生產 流程後加以使用或出售，且又於20X1年9月至12月再投入$10,000，以完善該生產流程。若甲 公司於20X1年底預估尚需於20X2年1月至4月間再投入$10,000，才能產生可回收金額為 $40,000的人工智慧生產流程，試為甲公司計算於20X1年底可認列為無形資產之總金額為多少？', '["$10,000", "$20,000", "$30,000", "$40,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00583', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年7月1日向銀行以10%的利率借款$200,000，甲公司以公允價值衡量該負債， 20X1年12月31日，此金融負債不含應計利息之公允價值為$195,000，該公允價值之變動與信 用風險無關。甲公司20X1年底財務報表中應如何報導此金融負債？ 利息費用 金融負債 評價利益（或損失）', '["$20,000 $200,000 $0", "$20,000 $195,000 $5,000", "$10,000 $195,000 $5,000", "$0 $195,000 $(15,000)"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00584', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年4月1日折價發行公司債籌措資金。有關此公司債的會計處理，公司係採攤銷 後成本法。惟錯誤使用直線法而非正確之有效利息法攤銷公司債折價。試問此錯誤對20X1年 12月31日之財務報表影響為何？ 債券帳面金額 保留盈餘', '["高估 高估", "低估 低估", "高估 低估", "低估 高估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00585', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '臺東公司於20X1年1月2日發行股票8,000股，面額$20，每股售價$22。該公司核定股數為20,000 股。公司今年發生下列庫藏股票交易事項：2月21日購回庫藏股票200股，每股購價$23；3月 15日出售庫藏股票200股，每股售價$25；5月28日購回庫藏股票200股，每股購價$25；6月4日 出售庫藏股票200股，每股售價$24；9月12日購回庫藏股票200股，每股售價$27。則該20X1年 底庫藏股票及由庫藏股票交易產生之資本公積餘額各為多少？', '["$4,600，$100", "$4,600，$200", "$5,400，$200", "$5,400，$400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00586', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列有關權益交割股份基礎給付交易衡量日之敘述，何者正確？', '["衡量日在給與日之後", "衡量日即為給與日", "與非員工交易之衡量日為企業取得商品或對方提供勞務之日，與員工交易之衡量日為給與日", "與非員工交易之衡量日為給與日，與員工交易之衡量日為企業取得商品或對方提供勞務之日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00587', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '高雄公司宣告以土地作為財產股息發放，相關資料如下： 公允價值 宣告日 20X1/4/20 $400,000 除息日 20X1/5/2 $350,000 發放日 20X1/5/20 $380,000 該土地在高雄公司的帳面價值為$250,000，則高雄公司在20X1年，對土地之處分應認列多少 利益？', '["$0", "$100,000", "$130,000", "$150,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00588', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列有關企業發行金融工具之敘述，何者錯誤？', '["金融工具為權益工具的關鍵特性為發行人可無條件避免（拒絕）：㉑支付現金或其他金融資 產給另一方，或㉒按潛在不利於發行人之條件與另一方交換金融資產或金融負債之合約義務", "發行人若發行可贖回的特別股，企業有盈餘時必須發放特別股股利，此特別股分類為金融 負債", "發行人若發行有到期日且須強制贖回的特別股，此特別股分類為金融負債", "發行人若發行之特別股若依經濟實質分類為負債，但其在法律形式上仍為權益，故該特別 股股利係屬於盈餘分配"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00589', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '和平公司20X1年期末權益項目餘額為股本$10,000,000、保留盈餘$250,000、庫藏股$100,000。 20X2年度淨利$125,000，且20X2年曾發生過下列交易：⑴宣告並發放股票股利$40,000；⑵出 售設備損失$10,000；⑶認列商譽之減損$10,000；⑷於20X2年1月1日更正20X1年初之帳務錯 誤事項，當時對購入耐用年限3年之設備$30,000（採直線法折舊，殘值為0）卻以費用入帳； ⑸全數出售庫藏股票獲得現金$90,000。則該公司20X2年底保留盈餘之正確餘額為多少？', '["$355,000", "$345,000", "$335,000", "$325,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00590', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '於計算每股盈餘時，若去年約定之或有發行股份之所有條件恰好於今年期末均已全部達成， 則下列敘述何者正確？', '["計算當年度基本每股盈餘時，或有發行應增加之普通股數為零", "計算當年度稀釋每股盈餘時，或有發行應增加之普通股數視為期初已發行", "僅", "正確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
